       job_code as code,
       job_name as name
  from batch.job_definition
 where tenant_id = #{tenantId}
   and window_code = #{configCode}

select id,
       job_code as code,
       job_name as name
  from batch.job_definition
 where tenant_id = #{tenantId}
   and worker_group = #{configCode}
